class Solution:
    def trailingzeros(self, n: int) -> int:
        count = 0
        while n > 0 and n % 2 == 0:
            count += 1
            n = n // 2
        return count

def main(input_file, output_file):  # type: ignore
    with open(input_file, 'r') as f_in, open(output_file, 'w+') as f_out:
        t = int(f_in.readline())
        for _ in range(t):
            n = int(f_in.readline())
            sol = Solution()
            f_out.write(str(sol.trailingzeros(n)) + '')

if __name__ == '__main__':
    main('input.txt', 'output.txt')

