#include <bits/stdc++.h>
using namespace std;
class Solution {
public:
    int trailingzeros(int n) {
        int count = 0;
        while (n > 0 && n % 2 == 0) {
            count++;
            n = n / 2;
        }
        return count;
    }
};
int main() {
    Solution sol;
    int t;
    cin >> t;
    while (t--) {
        int n;
        cin >> n;
        cout << sol.trailingzeros(n) << endl;
    }
    return 0;
}
